from flask import Flask, request, jsonify
import json

app = Flask(__name__)

# In-memory storage for labels
labels = {}

@app.route('/label', methods=['POST'])
def label_image():
    data = request.get_json()
    image_id = data['image_id']
    annotator_id = data['annotator_id']
    label = data['label']

    if image_id not in labels:
        labels[image_id] = []

    labels[image_id].append((annotator_id, label))

    return jsonify({'status': 'success'}), 200

@app.route('/train', methods=['GET'])
def train_model():
    # Aggregate labels using majority voting
    aggregated_labels = {}
    for image_id, annotator_labels in labels.items():
        label_counts = {}
        for _, label in annotator_labels:
            if label not in label_counts:
                label_counts[label] = 0
            label_counts[label] += 1

        # Find the most common label
        aggregated_label = max(label_counts, key=label_counts.get)
        aggregated_labels[image_id] = aggregated_label

    # Train model on aggregated labels (simplified example)
    model = {'aggregated_labels': aggregated_labels}
    return jsonify(model), 200

if __name__ == '__main__':
    app.run(debug=True)